#include <stdio.h>
#include <stdlib.h>

// Function to perform DFS
void dfs(int** mat, int* visited, int i, int j, int n, int m) {
    if (i < 0 || i >= n || j < 0 || j >= m || mat[i][j] != 'O' || visited[i][j]) return;
    visited[i][j] = 1;
    dfs(mat, visited, i - 1, j, n, m);
    dfs(mat, visited, i + 1, j, n, m);
    dfs(mat, visited, i, j - 1, n, m);
    dfs(mat, visited, i, j + 1, n, m);
}

// Function to solve the problem
void solve(int** mat, int n, int m) {
    int** visited = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        visited[i] = (int*)malloc(m * sizeof(int));
        for (int j = 0; j < m; j++) visited[i][j] = 0;
    }
    // Perform DFS from the boundary
    for (int i = 0; i < n; i++) {
        dfs(mat, visited, i, 0, n, m);
        dfs(mat, visited, i, m - 1, n, m);
    }
    for (int j = 0; j < m; j++) {
        dfs(mat, visited, 0, j, n, m);
        dfs(mat, visited, n - 1, j, n, m);
    }
    // Replace all unvisited 'O' with 'X'
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (mat[i][j] == 'O' && !visited[i][j]) mat[i][j] = 'X';
        }
    }
    // Free the memory
    for (int i = 0; i < n; i++) free(visited[i]);
    free(visited);
}

